const ListaDeBrinquedosNoEvento = (props) => {
    let evento = props.evento, i = 0;    
    return(
        <div className="col-md-12 brinquedosListaEventos d-flex flex-wrap">
            {evento.brinquedos.error ? 
                <div>
                    Não foi possível obter os brinquedos do evento
                </div>
                :
                evento.brinquedos.map((brinquedo)=>{
                    if(brinquedo.hasOwnProperty('error')){
                        return(
                            <div>{brinquedo.error}</div>
                        )
                    } else {
                        return(
                            <div key={i++} id="brinquedo_individual">
                                <div className="modulo_brinquedo p-2">
                                    <div className="nome_brinquedo letra_bem_pequena">{brinquedo.nome}</div>
                                    <div className="modulo_brinquedo">
                                        <img alt={brinquedo.nome} className="icone_brinquedo" src={"http://localhost:9000/imagem/"+brinquedo.imagem} height="40px"  />
                                    </div>
                                </div>
                            </div>)
                        }
                }, i)
                
            }
        </div>
    )
}

export default function CelulaEvento(props){

    return(
        <div className="linkFake">
            <div className="celula celulaEvento">
                <fieldset className="field_set_modulo_evento borda_azul">
                    <legend className="w-auto"><span>Evento id: </span><span className="idListaEventos">{props.evento.id_evento}</span></legend>
                    <div className="row container">
                        <div className="col-md-12 "><span className='nomeClienteListaEventos'>{props.evento.nome_cliente}</span></div>
                        <div className="col-md-6 dataListaEventos"><span>Data:&nbsp;</span><span>{props.evento.data_evento}</span></div><div className="col-md-6"><span>Valor a receber:&nbsp;R$</span><span>{props.evento.valor_total},00</span></div>
                        <div className="col-md-5">
                            <span>Telefone: </span><span className="telefone_cliente">{props.evento.telefone}</span>
                        </div>
                        <div className="col-md-5">
                            <span>Telefone Recado: </span><span className="telefone_recado">{props.evento.telefone_recado}</span>
                        </div>
                        <div className="col-md-2">
                            <span>Status: </span><span className="status">{props.evento.status}</span>
                        </div>
                        <div className="col-md-12 enderecoListaEventos"></div>
                        <div className="col-md-12">
                            Brinquedos:
                        </div>
                        <div>
                            <ListaDeBrinquedosNoEvento evento={props.evento} />                                            
                        </div>
                    </div>
                </fieldset>
            </div>
        </div>
    )    
}
